        marginBottom: mobile ? 16 : 20, transition: "all 0.4s"
      }}>
        <div style={{ width: 6, height: 6, borderRadius: "50%", background: item.color }} />
      </div>
      <h3 style={{
        fontFamily: "'Cormorant Garamond',Georgia,serif",
        fontSize: mobile ? 18 : 22, fontWeight: 700, color: "#0b1d3a",
        marginBottom: 10, lineHeight: 1.2
      }}>{item.title}</h3>
      <p style={{
        fontSize: mobile ? 13 : 14, color: "#777", lineHeight: 1.75,
        fontFamily: "'Outfit',sans-serif"
      }}>{item.desc}</p>
    </div>
  );
}

